    const program =
        \\    ST t0, 200       ; store t0 (5)
        \\    ST t1, 201       ; store t1 (7)
        \\    LD t2, 200       ; t2 = 5
        \\    MOV t5, t2       ; save t2 value
        \\    LD t3, 201       ; t3 = 7
        \\    ADD t4, t5, t3   ; t4 = 12
        \\    MOV t0, t4       ; t0 = 12
        \\    HALT
    ;
