        \\    LDI t1, 1         ; right height
        \\    SUB t0, t0, t1    ; t0 = 1
        \\    ST t0, 62         ; balance factor
        \\    LD t0, 62         ; load balance factor
        \\    HALT
    ;
    const cpu = try runWithInput(allocator, program, &[_]i64{});
    try std.testing.expectEqual(@as(i64, 1), cpu.t27[0].trits);
}

